1094:
SELECT ((SELECT overall_rating FROM Player_Attributes JOIN Player ON Player_Attributes.player_api_id = Player.player_api_id WHERE Player.player_name = 'Ariel Borysiuk') - 
(SELECT overall_rating FROM Player_Attributes JOIN Player ON Player_Attributes.player_api_id = Player.player_api_id WHERE Player.player_name = 'Paulin Puel')) / 
(SELECT overall_rating FROM Player_Attributes JOIN Player ON Player_Attributes.player_api_id = Player.player_api_id WHERE Player.player_name = 'Paulin Puel') * 100 AS percentage_difference;

800:
SELECT CAST(SUM(CASE WHEN T2.colour = 'Blue' THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(T1.superhero_name) AS percentage_blue_eyes
FROM superhero AS T1
JOIN colour AS T2 ON T1.eye_colour_id = T2.id;

640:
SELECT 
    (SELECT SUM(ViewCount) FROM posts WHERE OwnerDisplayName = 'Mornington') -
    (SELECT SUM(ViewCount) FROM posts WHERE OwnerDisplayName = 'Amos') AS ViewCountDifference;

352:
SELECT CAST(COUNT(CASE WHEN T1.language = 'Chinese Simplified' THEN 1 ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage
FROM foreign_data AS T1
JOIN cards AS T2 ON T1.uuid = T2.uuid;

